import java.io.BufferedReader;
import java.io.BufferedWriter;
import java.io.IOException;
import java.io.InputStreamReader;
import java.math.BigDecimal;
import java.math.RoundingMode;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.List;

/**
 * REMIT - a remittance advice written with WRITE ... FROM, translated from
 * COBOL 85. Faithful variant: exact COBOL behavior over Java idiom.
 *
 * Each COBOL WRITE REMIT-REC FROM WS-LINE is MOVE WS-LINE TO REMIT-REC
 * followed by WRITE REMIT-REC: the working-storage line is built (key +
 * amount), copied into the record area, and the record written. This
 * translation builds each line and writes it - the move made explicit -
 * to a real file (a temp path standing in for remit.dat), then serializes
 * its contents to stdout after the display lines, mirroring the harness
 * contract for file modules.
 */
public final class Remit {

    /** COMPUTE WS-CHARGE ROUNDED = WS-GROSS * 15 / 1000. */
    private static final BigDecimal CHARGE_RATE = new BigDecimal("15");
    private static final BigDecimal THOUSAND = new BigDecimal("1000");

    /** ADD 1 TO WS-ROWS: one increment per record written. */
    private static final BigDecimal ONE_ROW = new BigDecimal("1");

    /** PIC 9(7)V99 capacity (WS-GROSS / WS-CHARGE / WS-NET). */
    private static final BigDecimal PIC_9_7_V99_MODULUS = new BigDecimal("10000000");

    public static void main(String[] args) throws IOException {
        BufferedReader in = new BufferedReader(new InputStreamReader(System.in));

        String acctId = readLine(in);                                    // WS-ACCT-ID PIC X(8)
        BigDecimal gross = numval(readLine(in), PIC_9_7_V99_MODULUS);    // WS-GROSS PIC 9(7)V99

        BigDecimal charge = gross.multiply(CHARGE_RATE).divide(THOUSAND)
                .setScale(2, RoundingMode.HALF_UP)
                .remainder(PIC_9_7_V99_MODULUS);
        BigDecimal net = gross.subtract(charge).remainder(PIC_9_7_V99_MODULUS);

        // OPEN OUTPUT / WRITE FROM x3 / CLOSE: each WRITE FROM builds the
        // WS line, moves it into the record area and writes the record.
        Path advice = writeAdvice(gross, charge, net);
        BigDecimal rows = BigDecimal.ZERO; // WS-ROWS PIC 9 VALUE ZERO
        rows = rows.add(ONE_ROW);
        rows = rows.add(ONE_ROW);
        rows = rows.add(ONE_ROW);

        StringBuilder out = new StringBuilder();
        out.append("ACCT_ID=").append(acctId).append('\n');
        out.append("ROWS=").append(rows.toPlainString()).append('\n');
        System.out.print(out);

        // Serialize the file's actual contents (read back, not echoed),
        // mirroring the harness wrapper's `cat` of the legacy remit.dat.
        serializeAndDelete(advice);
    }

    /** The advice file: AMT=, CHG=, NET= records, one WRITE FROM each. */
    private static Path writeAdvice(BigDecimal gross, BigDecimal charge, BigDecimal net) throws IOException {
        Path advice = Files.createTempFile("remit", ".dat");
        try (BufferedWriter w = Files.newBufferedWriter(advice)) {
            // WRITE REMIT-REC FROM WS-LINE: build the line, move, write.
            String recordArea = "AMT=" + gross.toPlainString();
            w.write(recordArea);
            w.newLine();
            recordArea = "CHG=" + charge.toPlainString();
            w.write(recordArea);
            w.newLine();
            recordArea = "NET=" + net.toPlainString();
            w.write(recordArea);
            w.newLine();
        }
        return advice;
    }

    /** Emit the file's contents to stdout, then remove the temp file. */
    private static void serializeAndDelete(Path advice) throws IOException {
        List<String> lines = Files.readAllLines(advice);
        for (int i = 0; i < lines.size(); i = i + 1) {
            System.out.write((lines.get(i) + "\n").getBytes());
        }
        System.out.flush();
        Files.deleteIfExists(advice);
    }

    /** ACCEPT: one value per stdin line. */
    private static String readLine(BufferedReader in) throws IOException {
        String line = in.readLine();
        if (line == null) {
            System.err.println("REMIT: missing input line");
            System.exit(3);
        }
        return line.trim();
    }

    /** FUNCTION NUMVAL then the store into PIC 9(7)V99. */
    private static BigDecimal numval(String s, BigDecimal capacity) {
        try {
            return new BigDecimal(s.trim()).setScale(2, RoundingMode.DOWN).remainder(capacity);
        } catch (NumberFormatException e) {
            System.err.println("REMIT: invalid numeric input: " + s);
            System.exit(3);
            return BigDecimal.ZERO;
        }
    }
}
